// Import necessary modules from ethers.js
const { ethers } = require("ethers");

async function swapTokens(signer, tokenAAddress, tokenBAddress, dexAddress, amountIn) {
    // Define the ERC20 ABI for token approval and transfer functions
    const ERC20_ABI = [
        "function approve(address spender, uint256 amount)",
        "function allowance(address owner, address spender)",
        "function balanceOf(address account)"
    ];

    // Create a new contract instance for Token A
    const tokenA = new ethers.Contract(tokenAAddress, ERC20_ABI, signer);

    // Approve the DEX to spend up to maximum uint256 tokens from user's wallet
    const maxUint256 = ethers.constants.MaxUint256;
    const approvalTx = await tokenA.approve(dexAddress, maxUint256);
    await approvalTx.wait();

    // Define the DEX ABI for swapping functions
    const DEX_ABI = [
        "function swapExactTokensForTokens(uint amountIn, uint amountOutMin, address[] path, address to, uint deadline)"
    ];

    // Create a new contract instance for the DEX
    const dex = new ethers.Contract(dexAddress, DEX_ABI, signer);

    // Set the minimum output token quantity (for this example, we set it to 0)
    const amountOutMin = 0;

    // Define the path for swapping Token A to Token B
    const path = [tokenAAddress, tokenBAddress];

    // Execute the swap function in the DEX contract
    const swapTx = await dex.swapExactTokensForTokens(
        amountIn,
        amountOutMin,
        path,
        signer.address,
        Math.floor(Date.now() / 1000) + 60 * 20 // Deadline is set to 20 minutes from now
    );
    await swapTx.wait();

    console.log("Token swap successful!");
}

